INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$Masterless, peer-to-peer architecture$q$, $q$Every node in a Cassandra cluster is equal and can serve reads and writes, eliminating single points of failure and simplifying horizontal scaling.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$Linear horizontal scalability$q$, $q$Throughput and storage capacity scale close to linearly by adding more nodes, without downtime or complex resharding operations.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$Tunable consistency$q$, $q$Reads and writes can specify consistency levels per query, letting teams balance consistency, latency, and availability for each use case.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$Multi-datacenter and multi-cloud replication$q$, $q$Built-in replication strategies let clusters span multiple data centers or cloud regions for disaster recovery and low-latency global access.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$Wide-column, flexible schema$q$, $q$Tables support sparse, flexible columns per row, suited to semi-structured and rapidly evolving data models.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$CQL (Cassandra Query Language)$q$, $q$A SQL-like query language makes Cassandra approachable for teams familiar with relational syntax, despite the underlying non-relational model.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$High write throughput$q$, $q$Cassandra's log-structured storage engine (memtables plus SSTables) is optimized for extremely fast, append-heavy writes at massive scale.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$Fully open source, no vendor lock-in$q$, $q$Licensed under Apache License 2.0 with governance by the Apache Software Foundation, so there is no proprietary license fee or single controlling vendor.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$Free, open source, and battle-tested at massive scale by companies like Apple and Netflix$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$No single point of failure; clusters keep serving traffic through node and even data-center outages$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$Scales horizontally in a near-linear fashion by simply adding nodes$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$Strong multi-datacenter replication support out of the box$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$Large, mature ecosystem of drivers, tools, and third-party managed hosting options$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$Steep operational learning curve; data modeling and cluster tuning require real Cassandra-specific expertise$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$No native joins, foreign keys, or full multi-row ACID transactions like a relational database$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$Query patterns must be designed upfront around table structure, making ad-hoc analytics difficult$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$Running it well in production often requires commercial support or managed services, adding cost$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$Compaction and repair operations can be resource-intensive if not properly tuned$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$Is Apache Cassandra free to use?$q$, $q$Yes. Cassandra is fully open source under the Apache License 2.0, with no licensing fees. Costs only arise from the infrastructure you run it on or from optional commercial support and managed hosting services offered by third-party vendors.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$Who owns or controls Apache Cassandra?$q$, $q$No single company owns Cassandra. It is governed by the Apache Software Foundation as a community-driven open-source project. Companies such as DataStax, Instaclustr (part of NetApp), and Apple employ core contributors and offer commercial products around it, but the project itself is vendor-neutral.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$What is the current stable version of Cassandra?$q$, $q$As of mid-2026 the actively supported release line is the 5.0.x series, with 5.0.8 among the recent updates, while the 4.1 series remains supported for existing deployments. A 6.0 alpha is publicly available for teams evaluating the next major release.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$What is Cassandra best used for?$q$, $q$Cassandra excels at write-heavy, high-availability workloads such as time-series and IoT data, messaging and notification systems, product catalogs, session storage, and any application that needs to stay online and accept writes even during infrastructure failures.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$How is Cassandra different from a relational database like PostgreSQL or MySQL?$q$, $q$Cassandra is a distributed, masterless, wide-column NoSQL store designed for horizontal scale and availability, whereas relational databases like PostgreSQL emphasize strong consistency, complex joins, and full ACID transactions on a typically vertically-scaled or primary-replica architecture.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$Does Cassandra support SQL?$q$, $q$Not standard SQL, but it provides CQL (Cassandra Query Language), a SQL-inspired language for defining schemas and querying data, designed specifically around Cassandra's distributed data model.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$Can Cassandra run across multiple cloud providers or regions?$q$, $q$Yes. Cassandra has built-in support for multi-datacenter replication, which teams commonly use to run clusters across multiple cloud regions or even multiple cloud providers for redundancy and low-latency global access.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$Do I need Cassandra-specific expertise to run it in production?$q$, $q$Generally yes. Effective Cassandra usage requires careful data modeling around partition keys and query patterns, along with operational knowledge of compaction, repair, and capacity planning, which is why many organizations use managed Cassandra services or commercial support rather than self-operating clusters.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$High-volume IoT and time-series data ingestion$q$, $q$Cassandra's write-optimized storage engine and horizontal scalability make it a common backbone for ingesting continuous streams of sensor, telemetry, or event data at massive scale.$q$, $q$Platform and data engineering teams building IoT or observability infrastructure$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$Always-on messaging and notification systems$q$, $q$Its masterless architecture and multi-datacenter replication keep messaging and notification pipelines available even during regional outages or hardware failures.$q$, $q$Engineering teams at consumer and enterprise messaging companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$Global product catalogs and session stores$q$, $q$Cassandra supports large, flexible-schema catalogs and session data that need low-latency reads across globally distributed users.$q$, $q$E-commerce and large-scale SaaS engineering teams$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$architecture-and-history$q$, $q$Architecture and History$q$, 2, ARRAY[$q$Cassandra's defining trait is its masterless, peer-to-peer architecture: every node in a cluster is identical and can accept both reads and writes, and data is automatically partitioned and replicated across nodes using consistent hashing. This design, inherited from Amazon's internal Dynamo system, means there is no single point of failure and no need for manual failover when a node goes down. On top of that distributed foundation, Cassandra layers a wide-column data model similar to Google's Bigtable, where each row can have a flexible, sparse set of columns grouped into column families (tables), which makes it well suited to semi-structured, high-velocity data.$q$, $q$The project traces back to Facebook, where engineers Avinash Lakshman and Prashant Malik built it to solve the inbox search problem: search had to scale to hundreds of millions of users and billions of writes per day, something existing relational systems of the era could not handle affordably. Facebook released the code as open source in July 2008, and the Apache Software Foundation took it in as an incubator project in 2009, promoting it to a full top-level project in 2010. Since then, Cassandra has been developed entirely in the open by a community of contributors rather than by a single vendor, with major users including Apple, Netflix, Instagram, and thousands of smaller engineering teams.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('94894598-a30c-4b75-a310-5621b4bbab98', $q$where-cassandra-fits$q$, $q$Where Cassandra Fits and What It Trades Off$q$, 2, ARRAY[$q$Cassandra is optimized for workloads that need to ingest enormous volumes of writes continuously, remain available during hardware or network failures, and scale horizontally simply by adding more commodity nodes rather than buying bigger servers. This makes it a common choice for time-series and IoT telemetry, messaging and notification systems, product catalogs, session stores, and any system where uptime and write throughput matter more than complex ad-hoc queries. Its tunable consistency model lets teams choose, on a per-query basis, how many replicas must acknowledge a read or write, trading off strict consistency for lower latency and higher availability as needed.$q$, $q$What Cassandra deliberately does not offer is the flexibility of a general-purpose relational database: there are no multi-table joins, foreign key constraints, or full multi-row ACID transactions in the traditional sense, and effective use requires modeling tables around known query patterns rather than normalizing data the way a relational schema would. Running Cassandra well in production also demands genuine operational know-how around partition key design, compaction strategy, repair scheduling, and capacity planning, which is why many teams use managed Cassandra services or commercial support from companies like DataStax or Instaclustr rather than operating raw open-source clusters themselves.$q$]::text[], 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$Real-time Bot Score and Abuse Score$q$, $q$Castle scores every request in real time, typically within about 100 milliseconds, combining hundreds of signals into actionable risk scores.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$Device fingerprinting$q$, $q$High-accuracy device fingerprinting (claimed around 99.5 percent) helps identify returning devices tied to fraudulent activity.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$Edge plus in-app detection layers$q$, $q$Detection can run at the network edge, including a Cloudflare integration, and inside the application itself for layered protection against both bots and human-driven abuse.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$Behavioral biometrics$q$, $q$Signals like keystroke dynamics and browsing behavior help distinguish real users from automated scripts or session hijackers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$IP, proxy, and VPN intelligence$q$, $q$IP geolocation and proxy/VPN detection help flag traffic originating from suspicious infrastructure.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$Policy and rules engine$q$, $q$Teams configure allow, challenge, or deny policies in real time based on Castle's risk scores, without needing to write custom detection logic.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$Historical data and network analysis$q$, $q$Retention of up to 18 months of event history on Enterprise plans enables identification of connected fraud rings and repeat offenders.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$Webhooks and API-first integration$q$, $q$Castle exposes a developer-friendly API and webhook system so risk data can be wired directly into existing signup, login, and checkout flows.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$Transparent, linearly scaling usage-based pricing with a genuine free evaluation tier$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$Fast, sub-200ms risk scoring suitable for real-time signup and login flows$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$Dual-layer edge plus in-app detection catches both bots and sophisticated human-driven abuse$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$Strong customer base of well-known consumer platforms lends credibility$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$Developer-friendly API and documentation make self-serve integration realistic$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$Enterprise pricing (starting around $4,000/month) can be a significant jump for growing companies$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$Full pricing details for Enterprise-level Monthly Tracked User plans are not public and require sales contact$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$As with any behavioral fraud tool, false positives are possible and require tuning to avoid blocking legitimate users$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$Smaller company size relative to larger fraud-platform competitors may mean fewer specialized integrations for niche industries$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$Free and entry-level Pro tiers have lower rate limits (1-5 requests/second) that fast-growing apps may outgrow quickly$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$What does Castle actually do?$q$, $q$Castle is an account security and fraud detection platform that analyzes signup, login, and in-app behavior in real time to detect and stop bots, account takeovers, fake account creation, and other forms of account abuse.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$How much does Castle cost?$q$, $q$Castle offers a free tier for evaluation (up to 1,000 calls/month), a self-serve Pro plan at $200/month for the first 100,000 calls plus $0.002 per additional call, and custom Enterprise pricing starting around $4,000/month with volume or Monthly Tracked User based billing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$When was Castle founded and by whom?$q$, $q$Castle was founded in 2015 in Malmo, Sweden by Sebastian Wallin and Johan Brissmyr. The founders relocated to the San Francisco Bay Area in 2016 to join Y Combinator's Winter 2016 batch.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$How fast does Castle return a risk decision?$q$, $q$Castle typically returns real-time risk assessments in around 100 milliseconds, making it usable inline in signup, login, and checkout flows without noticeably slowing the user experience.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$Does Castle work with Cloudflare?$q$, $q$Yes. Castle offers a direct integration for Cloudflare that allows detection to run at the network edge in addition to in-application analytics, giving customers a combined edge-plus-in-app defense layer.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$Who uses Castle?$q$, $q$Castle's customers include consumer and enterprise platforms such as Atlassian, Rockstar Games, Rakuten, Canva, and Framer, spanning gaming, e-commerce, productivity, and design software companies.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$What kind of fraud can Castle detect?$q$, $q$Castle is used to detect and prevent account takeovers, fake account creation, multi-accounting and promo abuse, SMS pumping fraud, content abuse, and automated API abuse.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$Is there a free trial for Castle?$q$, $q$Yes. Castle offers a free tier capped at 1,000 API calls per month specifically for evaluating the platform before going live, with no credit card required to start.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$Preventing account takeover on consumer apps$q$, $q$Castle's real-time device and behavioral risk scoring helps consumer platforms detect stolen-credential logins and session hijacking before an attacker can act.$q$, $q$Product and security teams at consumer-facing SaaS and marketplace companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$Blocking fake account creation and promo abuse$q$, $q$Signup-time risk scoring flags bot-driven and fraudulent account creation, protecting free trials, referral programs, and promotional offers from abuse.$q$, $q$Growth and trust-and-safety teams at freemium or promotion-driven products$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$Protecting APIs and login endpoints from automated attacks$q$, $q$Castle's API-level detection and edge integration help engineering teams block credential-stuffing and scripted abuse against authentication and other sensitive endpoints.$q$, $q$Engineering and platform security teams managing public-facing APIs$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, NULL, $q$["Up to 1,000 API calls per month","1 API request per second","3-day data retention","3 seats","1 environment","Documentation-based support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$Pro$q$, $q$$200/month for first 100,000 calls, then $0.002 per additional call$q$, $q$Monthly, pay-as-you-go$q$, NULL, $q$["Unlimited calls with no contractual minimums","5 API requests per second","7-day data retention","5 seats","2 environments","Chat and email support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$Enterprise$q$, $q$Custom, starting around $4,000/month$q$, $q$Custom (Monthly Tracked User or volume-based)$q$, NULL, $q$["Unlimited API requests per second","Up to 18 months of data retention","Unlimited seats and environments","Dedicated Slack channel and SLA","Querying API access","Tailored MTU or volume pricing"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$how-castle-works$q$, $q$How Castle Detects and Stops Fraud$q$, 2, ARRAY[$q$Castle's core value proposition is combining two layers of defense: edge-level filtering that intercepts obviously automated or malicious traffic before it reaches a customer's servers, and in-application analytics that continue monitoring user behavior after a session begins, where more sophisticated attacks tend to hide. This dual-layer model, including a direct Cloudflare integration for edge deployment, lets Castle catch both blunt bot traffic and more nuanced account takeover attempts carried out by real people using stolen credentials or session hijacking techniques.$q$, $q$Underlying both layers is a risk-scoring engine that ingests device fingerprints, behavioral biometrics such as typing patterns and mouse movement, IP geolocation and proxy or VPN detection, and email reputation data, producing real-time Bot Score and Abuse Score outputs that typically resolve within about 100 milliseconds. Development teams can wire these scores into policy rules, ranging from silently allowing a request to challenging it with additional verification to denying it outright, and Castle retains historical event data, up to 18 months on higher-tier plans, to support deeper network analysis that can surface clusters of related fraudulent accounts or devices.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bfa13736-5cdf-4dab-aa42-a840ea9719c5', $q$pricing-and-fit$q$, $q$Pricing Structure and Who Castle Is For$q$, 2, ARRAY[$q$Castle markets its pricing as transparent and linearly scaling, in contrast to fraud-prevention vendors that require lengthy sales cycles for any pricing information. The free tier, capped at 1,000 API calls a month, exists purely for evaluation before going live. The Pro tier is self-serve at $200 per month for the first 100,000 calls, with overages billed at $0.002 per additional call and no long-term contractual minimums, making it accessible to startups and mid-sized companies that want to get started without an enterprise sales process. Larger organizations that need custom Monthly Tracked User pricing, extended data retention up to 18 months, dedicated Slack channels, and formal SLAs move into Enterprise agreements that start around $4,000 per month.$q$, $q$Given its customer roster, which includes consumer platforms like Canva and Rockstar Games alongside marketplaces like Rakuten, Castle tends to fit best for consumer-facing digital products and marketplaces with meaningful sign-up and login volume, where account takeover, fake account creation, and promo or content abuse are ongoing operational problems. Its developer-first integration model and self-serve pricing tier make it a reasonable starting point for engineering teams that want to add fraud detection without an immediate enterprise procurement process, while its Enterprise tier and edge integrations serve larger platforms that need deeper historical analysis and guaranteed support.$q$]::text[], 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$Centralized customer health dashboard$q$, $q$Aggregates usage, support, and engagement data from connected tools into a single view of each account's health.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$Proactive churn-risk alerts$q$, $q$Automated alerts notify customer success managers when key usage signals drop, enabling intervention before renewal risk escalates.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$Tool stack integrations$q$, $q$Connects with CRM, support, billing, and product analytics systems already used by a company's revenue organization.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$Customer success workflows and playbooks$q$, $q$Supports structured playbooks for onboarding, adoption, renewal, and expansion motions across a CS team's book of business.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$Segmentation and account views$q$, $q$Lets teams segment accounts by health, tier, or lifecycle stage to prioritize outreach and resource allocation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$Combined Totango-Catalyst technology$q$, $q$Following the companies' merger, customers gain access to a broader combined feature set spanning both platforms' historical strengths.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$Renewal and expansion tracking$q$, $q$Surfaces upsell and expansion opportunities alongside renewal timelines to support revenue growth from existing accounts.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$Reporting for CS and revenue leadership$q$, $q$Provides reporting aimed at giving CS and sales leadership visibility into portfolio-wide account health and outcomes.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$Well-funded, established player in the customer success software category with a decade-old founding team$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$Strong enterprise and mid-market customer references, including SAP and GitHub$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$Merger with Totango expands the combined product's scale and capability set$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$Designed specifically for proactive account management rather than reactive support ticketing$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$Integrates with existing CRM and analytics tools rather than requiring a full stack replacement$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$Pricing is not publicly disclosed, requiring a sales demo before buyers can evaluate cost$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$Best suited to companies with dedicated customer success teams, less relevant for small businesses without CS headcount$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$Ongoing integration of Catalyst and Totango technology post-merger may create short-term product transition friction for some customers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$Easily confused with the unrelated Catalyst by Zoho developer platform when searching generically for Catalyst$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$As an enterprise CS platform, implementation and integration setup likely requires meaningful onboarding time$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$Is Catalyst (catalyst.io) the same as Catalyst by Zoho?$q$, $q$No. Catalyst at catalyst.io is a customer success platform for CS and revenue teams, founded in 2017 by Edward Chiu and Kevin Chiu. Catalyst by Zoho is a completely separate serverless backend-as-a-service platform built by Zoho Corporation for software developers. The two products are unrelated aside from sharing a name.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$What does Catalyst (the customer success platform) actually do?$q$, $q$It centralizes customer data from a company's existing tools into a single account health view, and gives customer success teams proactive alerts and workflows to reduce churn and drive renewal and expansion.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$Who founded Catalyst and when?$q$, $q$Catalyst was founded in 2017 in New York City by brothers Edward Chiu and Kevin Chiu.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$Has Catalyst been acquired or merged with another company?$q$, $q$Yes. Catalyst Software has merged with Totango, another established customer success platform, and the combined company now markets itself as offering unified customer growth solutions.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$How much does Catalyst cost?$q$, $q$Catalyst does not publish pricing publicly. Prospective customers need to request a demo to receive a customized quote, which is standard practice for enterprise customer success software.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$Who are Catalyst's typical customers?$q$, $q$Catalyst serves customer success and revenue teams primarily at B2B software companies, with publicly referenced customers including SAP, GitHub, Schneider Electric, Dynatrace, Aircall, Braze, Fivetran, and Heap.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$How much funding has Catalyst raised?$q$, $q$Catalyst raised approximately $63.4 million in venture funding through a Series C round, with investors including Accel, Spark Capital, and Ludlow Ventures.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$Is Catalyst suitable for small businesses?$q$, $q$Catalyst is generally built for companies with dedicated customer success organizations and a meaningful base of paying accounts to manage, making it more suited to mid-market and enterprise B2B companies than very small businesses.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$Proactive churn prevention for SaaS accounts$q$, $q$CS teams use Catalyst's health scoring and alerts to spot at-risk accounts early and intervene before a renewal is lost.$q$, $q$Customer success managers and CS leadership at B2B SaaS companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$Unifying fragmented customer data$q$, $q$Companies with data spread across CRM, support, billing, and analytics tools use Catalyst to consolidate it into one account view.$q$, $q$RevOps and customer success operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$Identifying expansion and upsell opportunities$q$, $q$By tracking usage trends and engagement, CS and sales teams use Catalyst to flag accounts ready for upsell or expansion conversations.$q$, $q$Account management and sales teams focused on net revenue retention$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$what-catalyst-is-and-isnt$q$, $q$What Catalyst Is (and Is Not)$q$, 2, ARRAY[$q$Catalyst, accessible at catalyst.io, is a customer success platform, a category of B2B software used by customer success and account management teams to monitor account health, track product usage, and manage renewal and expansion workflows. It should not be confused with Catalyst by Zoho, an unrelated serverless backend-as-a-service and full-stack app development platform built by Zoho Corporation for software developers. The two products happen to share a name but were built by entirely different companies, for entirely different audiences, with no technical or corporate connection between them. Buyers and researchers should confirm which Catalyst they mean before evaluating features or pricing, since search results for the plain term Catalyst frequently surface both products interchangeably.$q$, $q$This Catalyst was founded in 2017 by brothers Edward Chiu and Kevin Chiu in New York City and grew into a venture-backed company that raised roughly $63.4 million through a Series C round, with investors including Accel, Spark Capital, and Ludlow Ventures. The company's core pitch was being the most intuitive customer success platform on the market, aimed at making it easier for CS teams to see account health and usage signals without needing heavy technical configuration.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a2641553-2df4-4aff-b662-314b0dddc12d', $q$totango-merger-and-use$q$, $q$The Totango Merger and How Teams Use Catalyst$q$, 2, ARRAY[$q$A defining recent event for the company is its merger with Totango, another well-known customer success platform vendor. Rather than operating as two competing products, the combined organization now positions itself as delivering more complete customer growth solutions by pairing Catalyst's product experience with Totango's technology and customer relationships, aimed at helping CS and sales teams drive retention and expansion together rather than working from separate systems.$q$, $q$In day-to-day use, Catalyst connects to the other tools a company already relies on, such as CRM, support, billing, and product analytics platforms, consolidating that data into a single customer view. Customer success managers use this view to build account health scores, track engagement trends, and receive proactive alerts, for instance when a customer's usage of a feature considered critical to their success starts declining, giving the team a chance to intervene before the account churns. This proactive, centralized approach is what the company's customer roster, including SAP, GitHub, Schneider Electric, Dynatrace, Aircall, Braze, Fivetran, and Heap, is reported to rely on for managing large books of business.$q$]::text[], 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Function-as-a-Service compute$q$, $q$Supports five function types in Java and Node.js: Basic I/O, Advanced I/O, Event Functions, periodic/scheduled functions, and Integration Functions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Managed Data Store$q$, $q$A relational backend data store for structured application data, provisioned and scaled automatically without server management.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$File storage and caching$q$, $q$Built-in file storage and a caching layer let applications store assets and speed up repeated data access without extra infrastructure setup.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Zia AI and ML services$q$, $q$Access to Zoho's Zia AI engine for capabilities like OCR and object detection, usable directly from Catalyst functions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Circuits workflow orchestration$q$, $q$A visual workflow orchestration tool for coordinating multi-step application logic across functions and services.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Elastic auto-scaling$q$, $q$Compute automatically scales up during traffic spikes and down during idle periods, without manual server capacity planning.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Multi-platform SDKs$q$, $q$Native SDKs for iOS, Android, and web enable fully custom client applications built on top of Catalyst's backend services.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Free tier forever plus flexible billing$q$, $q$A generous, recurring free tier combined with a choice of pay-as-you-go or fixed-budget subscription billing models.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Genuinely useful free tier (70+ components) that renews every month, good for prototyping and small production apps$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Pay only for actual compute time consumed rather than idle server capacity, keeping costs efficient at small scale$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Deep integration with the broader Zoho ecosystem of 55+ business applications is valuable for existing Zoho customers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Backed by Zoho Corporation, a large, profitable, established software company with long-term infrastructure stability$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Built-in AI/ML services (Zia) and workflow orchestration (Circuits) reduce the need for third-party add-ons$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Smaller developer mindshare and ecosystem compared to AWS Lambda, Google Cloud Functions, or Firebase$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Function support currently limited to Java and Node.js, narrower than some competing serverless platforms$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Easily confused with the unrelated standalone Catalyst customer success platform when searching generically$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Pricing structure (free tier plus pay-as-you-go with a subscription option) requires some study to estimate costs accurately at scale$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Best value is realized by teams already invested in the Zoho ecosystem; less compelling as a standalone choice outside that context$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Is Catalyst by Zoho the same as Catalyst at catalyst.io?$q$, $q$No. Catalyst by Zoho is a serverless backend-as-a-service platform for developers, built by Zoho Corporation. Catalyst at catalyst.io is an unrelated customer success platform founded separately in 2017 and later merged with Totango. They share only a name.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$What is Catalyst by Zoho used for?$q$, $q$It is used to build and host full-stack web and mobile applications without managing servers, providing serverless compute (functions), a managed database, file storage, caching, authentication, AI/ML services, and workflow orchestration in one platform.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$When did Zoho launch Catalyst?$q$, $q$Zoho publicly announced Catalyst on October 17, 2019, opening up the same internal serverless infrastructure that powers Zoho's own suite of business applications, with the platform reaching broader general availability in the years that followed.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Is Catalyst by Zoho free to use?$q$, $q$Yes, up to a point. Catalyst offers a free tier with more than 70 components available every month at no cost, plus a one-time $250 credit for first-time users. Usage beyond free-tier limits is billed pay-as-you-go with a $5 monthly minimum, or through an optional fixed subscription plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$What programming languages does Catalyst support for functions?$q$, $q$Catalyst currently supports building serverless functions in Java and Node.js across five function types: Basic I/O, Advanced I/O, Event Functions, periodic/scheduled functions, and Integration Functions.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Does Catalyst include AI and machine learning features?$q$, $q$Yes. Catalyst gives developers access to Zia, Zoho's AI engine, which provides capabilities such as optical character recognition and object detection that can be called directly from Catalyst functions.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Who owns Catalyst by Zoho?$q$, $q$Catalyst is a product of Zoho Corporation, a large, privately held, profitable software company founded in 1996 with dual headquarters in Chennai, India and Austin, Texas.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Is Catalyst a good fit for companies not already using Zoho products?$q$, $q$It can be, particularly for teams that want a genuinely free tier and simple usage-based pricing, but the platform's value is strongest for teams already invested in the broader Zoho ecosystem of business applications.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Building full-stack apps without managing servers$q$, $q$Developers use Catalyst's Function-as-a-Service compute and managed backend services to ship web and mobile apps without provisioning infrastructure.$q$, $q$Independent developers and small engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Extending Zoho business applications with custom logic$q$, $q$Businesses already using Zoho CRM, Books, or other Zoho apps use Catalyst's Integration Functions to build custom automations and extensions on the same infrastructure.$q$, $q$IT teams and developers at companies standardized on Zoho$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Adding AI capabilities like OCR without building ML infrastructure$q$, $q$Teams use Catalyst's Zia integration to add document OCR or object detection to applications without training or hosting their own models.$q$, $q$Product teams needing lightweight AI features on a budget$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Free Tier$q$, $q$$0$q$, $q$Monthly, renews forever$q$, NULL, $q$["70+ free components included every month","25,000 GB-seconds of serverless function compute","2 GB of Data Store storage","1,000 free GET requests in Cache","One-time $250 credit for first-time users"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Pay-As-You-Go$q$, $q$$5/month minimum once free tier is exceeded$q$, $q$Postpaid, monthly$q$, NULL, $q$["Billed only for resources actually consumed beyond the free tier","No separate subscription fee","Applies across functions, data store, storage, and caching","Suited to variable or unpredictable workloads"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$Subscription (example Basic plan)$q$, $q$From approximately $25/month$q$, $q$Monthly, fixed budget$q$, NULL, $q$["Predictable monthly billing for budgeting purposes","Zoho adds an extra $5 of resource allowance on top of the selected plan at no charge","Aimed at SMBs and enterprises needing consistent monthly allocation","Scales to higher-tier subscription plans for larger workloads"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$not-the-same-catalyst$q$, $q$A Distinct Product From the Standalone Catalyst$q$, 2, ARRAY[$q$Before evaluating features, it is worth stating clearly: Catalyst by Zoho is not the same product as Catalyst at catalyst.io, a standalone customer success platform founded in 2017 by Edward Chiu and Kevin Chiu that has since merged with Totango. Catalyst by Zoho is a developer-focused serverless application platform built by Zoho Corporation, an entirely different company, for an entirely different audience of software engineers rather than customer success teams. The two products happen to share the Catalyst name coincidentally, and anyone researching one should be careful not to conflate its features, pricing, or company background with the other.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8cd7aefe-b8d8-4c44-99fd-8bd25c94179b', $q$platform-capabilities$q$, $q$Platform Capabilities and Pricing Model$q$, 2, ARRAY[$q$Catalyst's central offering is Function-as-a-Service compute in Java and Node.js, split across five function types covering everything from simple request handling to large data streaming, event-driven triggers, scheduled tasks, and integrations with other Zoho products. Around that compute layer, Zoho bundles the managed backend services most applications need out of the box, including a relational Data Store, file storage, caching, authentication, and a workflow orchestration tool called Circuits, alongside access to Zia, Zoho's AI engine, for capabilities like OCR and object detection without building custom ML infrastructure. SDKs for iOS, Android, and web let developers build fully custom client applications on top of these backend services.$q$, $q$Pricing is structured to be accessible for small projects while scaling to production workloads. The free tier includes more than 70 components at no cost every month, refreshed automatically, plus a one-time $250 credit for first-time users. After exceeding free-tier limits, Catalyst defaults to postpaid pay-as-you-go billing with a $5 monthly minimum and no separate subscription charge, so cost tracks actual usage. Teams that prefer predictable monthly budgeting can instead opt into a subscription model, where Zoho's own example cites a Basic plan around $25 per month, with Zoho adding an extra $5 of resource allowance on top at no additional cost. This combination of a genuinely useful free tier, usage-based pricing, and Zoho's broader ecosystem integration makes Catalyst a practical option for teams already using other Zoho products, or for developers who want a serverless platform without negotiating enterprise cloud contracts.$q$]::text[], 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$Multi-platform expired domain aggregation$q$, $q$Pulls expired and auction domain listings from roughly 16-20 sources including GoDaddy, Dynadot, DropCatch, SnapNames, Catched, and Gname into one searchable database.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$Aged ccTLD regfee database$q$, $q$Maintains a database of over 100,000 aged country-code domains available to register directly at standard registration price rather than via auction.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$Automatic SEO metric enrichment$q$, $q$Every listed domain is enriched with Trust Flow, Citation Flow, Domain Authority, backlink counts, and referring domain data without manual lookup.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$Wayback Machine history integration$q$, $q$Surfaces historical snapshots for each domain so buyers can assess prior content and use before bidding.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$Advanced filtering$q$, $q$Supports filtering by domain length, TLD, language, technical stack, and content category to narrow large result sets quickly.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$REST API access$q$, $q$Provides programmatic access to expired-domain data for integration into custom tools, scripts, or acquisition workflows.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$MCP server for AI assistants$q$, $q$Lets AI coding assistants such as Claude, Cursor, and Windsurf query expired-domain data conversationally through the Model Context Protocol.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$Daily-updated inventory$q$, $q$Adds tens of thousands of newly discovered expired or dropping domains to its database every day.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$Consolidates dozens of auction platforms and SEO metric lookups into a single searchable tool$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$Includes both a REST API and an MCP server, unusual and useful for developers and AI-assisted workflows$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$Automatic SEO enrichment (Trust Flow, Citation Flow, Domain Authority, backlinks) saves significant manual research time$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$Entry-level Pro pricing (around EUR 39/month annualized) is accessible compared to enterprise domain intelligence tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$Built by a founder with direct domain-investing experience, so the workflow is designed around real practitioner needs$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$As a solo, bootstrapped project, long-term company stability and support capacity are less certain than with a larger vendor$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$Exact founding date and company details are not formally published, limiting transparency for buyers doing due diligence$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$Full pricing for the higher Authority and Authority plus tiers is not consistently published and requires checking the live pricing page$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$Free tier is limited to a small number of visible domains, making the paid Pro plan necessary for serious use$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$Coverage depends on the specific auction platforms integrated, so it may not include every registrar a buyer cares about$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$What is CatchDoms?$q$, $q$CatchDoms is an expired and pending-delete domain discovery platform that aggregates listings from many domain auction platforms and registrars, enriching each domain with SEO metrics like Domain Authority, Trust Flow, backlinks, and Wayback Machine history to help domain investors evaluate opportunities faster.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$Who built CatchDoms?$q$, $q$CatchDoms was built and is operated by Samir Belabbes, a solo founder with over a decade of SEO and web development experience, running it as a bootstrapped, pre-seed SaaS business.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$How much does CatchDoms cost?$q$, $q$CatchDoms offers a limited free tier plus a paid Pro plan priced at roughly EUR 39 per month billed annually (EUR 468/year) or EUR 89 per month billed monthly. Higher Authority and Authority plus tiers exist above Pro, though their exact published pricing was not consistently confirmed in public sources.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$Does CatchDoms have an API?$q$, $q$Yes. CatchDoms provides a REST API for programmatic access to its expired-domain database, allowing developers to integrate the data into their own tools, scripts, or acquisition pipelines.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$What is the CatchDoms MCP server?$q$, $q$CatchDoms offers a Model Context Protocol (MCP) server that lets AI coding assistants like Claude, Cursor, and Windsurf query expired-domain data conversationally, without needing to use the web interface directly.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$What SEO metrics does CatchDoms show for each domain?$q$, $q$CatchDoms enriches each domain with metrics including Trust Flow, Citation Flow, Domain Authority, backlink counts, referring domains, category classification, and historical Wayback Machine snapshots.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$Which auction platforms does CatchDoms aggregate?$q$, $q$CatchDoms pulls listings from a range of domain auction and registrar platforms, publicly cited sources include GoDaddy, Dynadot, DropCatch, SnapNames, Catched, Gname, BloomUp, UKBackorder, and DomainLore, among others.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$Who is CatchDoms designed for?$q$, $q$CatchDoms is designed for domain investors, SEO professionals, and entrepreneurs looking to find, evaluate, and acquire expired, dropped, or auctioned domains with built-in SEO metrics and historical data.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$Finding expired domains with strong backlink profiles$q$, $q$Domain investors use CatchDoms's automatic SEO enrichment to quickly identify expiring domains with valuable existing backlinks and authority metrics.$q$, $q$Domain investors and flippers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$Sourcing aged domains for new SEO projects$q$, $q$SEO professionals use the aged ccTLD regfee database and filtering tools to find registrable aged domains as a foundation for new content or affiliate sites.$q$, $q$SEO professionals and content site builders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$Automating domain research through AI assistants and APIs$q$, $q$Developers use the CatchDoms REST API or MCP server to pull expired-domain data directly into custom scripts or AI coding assistants for automated sourcing workflows.$q$, $q$Developers and technical domain acquisition teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$Free$q$, $q$$0$q$, $q$Free$q$, NULL, $q$["Limited number of visible domains (around 10)","Preview access to the live expired domains database","No API or MCP access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$Pro$q$, $q$EUR 39/month billed annually (EUR 468/year), or EUR 89/month billed monthly$q$, $q$Monthly or annual$q$, NULL, $q$["Full access to the live database across all aggregated auction platforms","CSV exports and expiry alerts","API and MCP access","SEO metric enrichment (Trust Flow, Citation Flow, Domain Authority, backlinks)"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$what-catchdoms-solves$q$, $q$The Problem CatchDoms Solves$q$, 2, ARRAY[$q$Domain investors and SEO professionals hunting for valuable expired or dropped domains have traditionally had to check many separate auction platforms manually every day, since no single registrar or marketplace lists all domains coming up for auction or deletion. On top of that, evaluating whether a given domain is actually worth bidding on typically requires pulling authority and backlink metrics from tools like Majestic or Ahrefs and manually reviewing a domain's history through the Wayback Machine, a slow, repetitive process when done across dozens of candidate domains a day. CatchDoms consolidates this workflow into a single searchable platform, aggregating listings from a wide set of auction and registrar sources and automatically attaching Trust Flow, Citation Flow, Domain Authority, backlink data, and Wayback history to each domain, so a user can filter and evaluate opportunities in one place rather than juggling a dozen browser tabs and separate subscriptions.$q$, $q$The platform was built by Samir Belabbes, who describes himself as a solo founder running CatchDoms as a bootstrapped, pre-seed SaaS business after more than ten years working in SEO and web development. According to his own account of building the product, the motivation came directly from his personal frustration as a domain investor checking roughly a dozen auction platforms every morning and manually cross-referencing SEO metrics and historical snapshots for each promising domain, a workflow CatchDoms was built specifically to automate.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d1c3bb57-a99a-486b-8024-b9dcc1367a4d', $q$api-mcp-and-pricing$q$, $q$API, MCP Access, and Pricing Structure$q$, 2, ARRAY[$q$Beyond its web-based search interface, CatchDoms exposes both a REST API and a Model Context Protocol (MCP) server, a notable and relatively unusual feature for a domain tool. The REST API lets developers pull expired-domain data programmatically into their own tools, scripts, or acquisition pipelines, while the MCP server allows AI coding assistants such as Claude, Cursor, and Windsurf to query the same expired-domain dataset conversationally, effectively letting a user ask an AI assistant to search for domains matching specific criteria without leaving their coding environment.$q$, $q$CatchDoms follows a freemium pricing structure. The free tier gives a limited preview of visible domains from the live database, while the Pro plan unlocks full access for roughly EUR 39 per month when billed annually (EUR 468 per year total) or EUR 89 per month billed monthly. Above Pro, the platform advertises Authority and Authority plus tiers aimed at more serious domain investors, with Authority reported to add access to a database of aged ccTLD domains registrable at standard price, a recurring call with the founder, and early access to features still in development, such as post-auction monitoring; specific published pricing for these higher tiers was not consistently available in public sources, so prospective buyers should confirm current numbers directly on the CatchDoms pricing page.$q$]::text[], 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Ultra-lightweight tracking script$q$, $q$The CatchJS script is reported at under 1.8KB after compression, minimizing page-weight impact compared to larger competing error trackers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Automatic JavaScript error capture$q$, $q$Captures unhandled errors with full stack traces and surrounding context automatically after a single script tag is added.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Core Web Vitals performance tracking$q$, $q$Measures real-user performance metrics including Largest Contentful Paint, Cumulative Layout Shift, and First Input Delay.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Privacy-respecting simple analytics$q$, $q$Tracks pageviews and time on page without invasive user-level tracking, appealing to privacy-conscious teams.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Click-trail and screenshot context$q$, $q$Captures the sequence of user actions and screenshots leading up to an error to speed up debugging.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Email error notifications$q$, $q$Sends real-time email alerts when new or high-frequency errors occur, included on every plan.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Dedicated Shopify app$q$, $q$Available as the Error Tracking with CatchJS app in the Shopify App Store for store owners without custom development resources.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Multi-domain and subdomain support$q$, $q$Higher tiers support monitoring across multiple domains with unlimited subdomains under each.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Extremely small script footprint minimizes impact on page load and Core Web Vitals scores$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Combines error tracking, performance monitoring, and simple analytics in one lightweight tool$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Straightforward, transparent per-tier pricing without complex seat-based licensing$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Dedicated Shopify app extends usability to non-developer e-commerce store owners$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$14-day free trial available on every plan with no long-term commitment required$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Smaller company and ecosystem than major competitors like Sentry, so integrations and community resources are more limited$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Pricing is comparatively high relative to logged-error volume once beyond the Development tier's 1,000-error allowance$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Feature depth (e.g., source-map deobfuscation, release tracking, advanced alerting rules) may be less extensive than larger dedicated error-tracking platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Best suited to smaller sites; the top Enterprise tier's 1,000,000-error allowance may still be limiting for very high-traffic applications$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Limited public information on the company itself (team size, funding) makes long-term vendor risk harder to assess$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$What does CatchJS do?$q$, $q$CatchJS is a JavaScript error tracking, performance monitoring, and simple analytics tool. After adding a single lightweight script tag to a website, it automatically captures unhandled errors with stack traces, tracks Core Web Vitals performance metrics, and records basic, privacy-respecting page analytics.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$How big is the CatchJS tracking script?$q$, $q$CatchJS reports its script as under 1.8KB after compression, which the company describes as up to 20 times smaller than many competing JavaScript error-tracking scripts.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$How much does CatchJS cost?$q$, $q$CatchJS has three tiers: Development starting at $44/month billed annually ($49/month monthly), Production starting at $79/month annually ($89/month monthly), and Enterprise starting at $449/month annually ($499/month monthly), each scaling by logged error volume and monitored URLs.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Does CatchJS work with Shopify?$q$, $q$Yes. CatchJS is available as a dedicated Shopify app called Error Tracking with CatchJS, listed in the Shopify App Store, letting store owners monitor JavaScript errors on their storefronts without custom development.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$What performance metrics does CatchJS track?$q$, $q$CatchJS tracks real-user Core Web Vitals metrics including Largest Contentful Paint, Cumulative Layout Shift, and First Input Delay, alongside pageviews and time-on-page analytics.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Is there a free trial for CatchJS?$q$, $q$Yes, every CatchJS plan includes a 14-day free trial to evaluate the product before committing to a paid subscription.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Where is CatchJS based?$q$, $q$CatchJS is based in Trondheim, Norway, and was founded in 2018.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Is CatchJS a good alternative to larger tools like Sentry?$q$, $q$CatchJS can be a good fit for teams that specifically want a very lightweight script and simple, transparent pricing, though larger platforms like Sentry offer deeper feature sets and larger integration ecosystems that may suit bigger or more complex engineering organizations better.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Lightweight error monitoring for performance-sensitive sites$q$, $q$Teams that care deeply about page-weight and Core Web Vitals use CatchJS's sub-2KB script to add error tracking without hurting load performance.$q$, $q$Frontend developers and performance-focused engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Shopify storefront error monitoring$q$, $q$Store owners use the Error Tracking with CatchJS Shopify app to catch JavaScript errors that could disrupt checkout or browsing on their storefront.$q$, $q$Shopify merchants and e-commerce developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Simple, privacy-friendly usage and performance insight$q$, $q$Small teams use CatchJS's built-in analytics and Core Web Vitals tracking as a lightweight alternative to running separate analytics and performance monitoring tools.$q$, $q$Indie developers and small product teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Development$q$, $q$$44/month billed annually, or $49/month billed monthly$q$, $q$Monthly or annual$q$, NULL, $q$["1,000 logged errors per month","1,000 log API calls per month","Performance metrics for 100 URLs","Pageviews for 10,000 URLs","1 domain plus unlimited subdomains","Email notifications, screenshots, click trails, priority support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Production$q$, $q$$79/month billed annually, or $89/month billed monthly$q$, $q$Monthly or annual$q$, NULL, $q$["100,000 logged errors per month","100,000 log API calls per month","Performance metrics for 1,000 URLs","Pageviews for 100,000 URLs","1 domain plus unlimited subdomains","Email notifications, screenshots, click trails, priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$Enterprise$q$, $q$$449/month billed annually, or $499/month billed monthly$q$, $q$Monthly or annual$q$, NULL, $q$["1,000,000 logged errors per month","1,000,000 log API calls per month","Performance metrics for 10,000 URLs","Pageviews for 1,000,000 URLs","25 domains plus unlimited subdomains","Email notifications, screenshots, click trails, priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$what-catchjs-does$q$, $q$What CatchJS Does$q$, 2, ARRAY[$q$CatchJS focuses on three connected problems web developers face after shipping code to production: knowing when JavaScript actually breaks for real users, understanding how pages perform for those same real users, and getting lightweight usage analytics without deploying a heavier tracking suite. After adding a single script tag, CatchJS automatically listens for unhandled JavaScript errors across a site and reports them with full stack traces and surrounding context, similar in concept to larger error-tracking platforms but built around a dramatically smaller script footprint, reported at under 1.8KB after compression, which the company markets as up to 20 times lighter than typical competing error trackers.$q$, $q$Alongside error capture, CatchJS records real-user performance metrics tied directly to Core Web Vitals and user experience, including Largest Contentful Paint, Cumulative Layout Shift, and First Input Delay, plus simple, privacy-conscious analytics covering pageviews and time on page. This combination lets a small team get error visibility, performance monitoring, and basic analytics from one lightweight tool instead of running three separate services, which is part of why CatchJS is also distributed as a dedicated Shopify app for store owners who want the same visibility without custom development work.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8e3a9ede-b812-4938-8daa-419a010507ee', $q$pricing-and-fit$q$, $q$Pricing Tiers and Who CatchJS Is Built For$q$, 2, ARRAY[$q$CatchJS's three pricing tiers scale primarily along logged error volume and the number of URLs being monitored for performance and pageviews, rather than along team seats or feature gating, which keeps the plans simple to reason about. The Development plan (from $44/month annually) fits small sites, staging environments, or early-stage products with modest error and traffic volume, covering 1,000 logged errors and 100 monitored URLs per month. The Production plan (from $79/month annually) is aimed at live, revenue-generating websites with higher error and traffic volume, offering 100x the error and pageview allowances of the Development tier. The Enterprise plan (from $449/month annually) is built for high-traffic applications or agencies managing many domains, supporting up to a million logged errors a month and coverage across 25 domains with unlimited subdomains.$q$, $q$Given its small script size and simple setup, CatchJS tends to suit small-to-midsize engineering teams, indie developers, and Shopify merchants who want error visibility and basic performance monitoring without the cost, complexity, or page-weight overhead of enterprise observability platforms like Sentry or Datadog. Its Norway-based, apparently small and independently run team also suggests a product built for a focused niche, script-weight-conscious error tracking, rather than an attempt to compete head-on with full-scale application performance monitoring suites.$q$]::text[], 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$Thousands of hosted JS and CSS libraries$q$, $q$Hosts over 4,000 open-source JavaScript and CSS libraries, publicly maintained on GitHub, with new libraries and versions continually added.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$Cloudflare global edge network$q$, $q$Files are served from Cloudflare's globally distributed CDN infrastructure, providing fast load times and high reliability worldwide.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$Zero setup, copy-paste integration$q$, $q$Developers simply copy a script or link tag from cdnjs.com to include a library, with no account, signup, or build step required.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$Fully free and open source$q$, $q$cdnjs has no cost, subscription tiers, or paywalled features; it is funded entirely by Cloudflare as a public service to the developer community.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$Massive scale and reliability$q$, $q$Reportedly serves over 200 billion requests per month and is used on more than 12 percent of all websites globally.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$Community-maintained library catalog$q$, $q$The list of hosted libraries and their versions is maintained through open contributions on GitHub rather than a closed internal process.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$Version-specific file URLs$q$, $q$Each library version is hosted at a distinct URL, letting developers pin a specific version rather than always pulling the latest release.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$Security-conscious infrastructure$q$, $q$Operated by Cloudflare, a major internet infrastructure and security company, giving cdnjs enterprise-grade operational reliability.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$Completely free with no signup, account, or payment required to use$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$Backed by Cloudflare's large-scale, reliable global CDN infrastructure$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$Extensive library catalog covering thousands of popular JavaScript and CSS packages$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$Simple copy-paste integration makes it ideal for quick prototyping and tutorials$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$Long operating history since 2011 has made it a trusted, widely recognized standard in web development$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$Loading third-party scripts from any public CDN introduces a small dependency on that CDN's uptime and security$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$Increasingly overshadowed by npm and bundler-based workflows for production applications, especially with modern frameworks$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$Library versions can lag behind the latest release depending on how quickly maintainers submit updates to the GitHub repository$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$No official support channel for issues beyond community GitHub contributions, unlike a commercial vendor with paid support$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$Being run by a single company (Cloudflare) means the project's continuity, while currently stable, ultimately depends on one organization's ongoing commitment$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$Is cdnjs free to use?$q$, $q$Yes. cdnjs is completely free and open source, with no signup, subscription, or payment required. It is funded and operated by Cloudflare as a public service to the web development community.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$Who owns cdnjs?$q$, $q$Cloudflare has fully owned and operated cdnjs since November 1, 2019, when original creators Ryan Kirkman and Thomas Davis formally transferred the project to them, citing technical and commercial reasons. Cloudflare had been cdnjs's infrastructure partner since June 2011.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$When was cdnjs created?$q$, $q$cdnjs was created in January 2011 by Ryan Kirkman and Thomas Davis, with the project publicly launched on GitHub on February 25, 2011.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$How many libraries does cdnjs host?$q$, $q$cdnjs has hosted over 4,000 distinct JavaScript and CSS libraries as of the last widely cited figures, with the catalog continuing to grow through community contributions on GitHub.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$How do I use a library from cdnjs?$q$, $q$Visit cdnjs.com, find the library and version you need, and copy the provided script or link tag into your HTML file. No account or installation is required, and Cloudflare's CDN handles delivery automatically.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$How does cdnjs compare to jsDelivr or unpkg?$q$, $q$cdnjs, jsDelivr, and unpkg are all free, open-source CDNs for JavaScript and CSS libraries with broadly similar purposes. cdnjs is distinguished by its long operating history since 2011 and its direct operation by Cloudflare's infrastructure.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$Is cdnjs suitable for production websites?$q$, $q$Yes, many production websites use cdnjs, particularly for well-known, stable libraries, though many modern applications increasingly use npm-based bundlers for more granular version control and to avoid third-party request dependencies.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$How much traffic does cdnjs handle?$q$, $q$cdnjs has been reported to serve over 200 billion requests per month and is used on more than 12 percent of all websites, reflecting its scale as one of the most widely used CDNs for open-source libraries.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$Rapid prototyping without a build pipeline$q$, $q$Developers use cdnjs to quickly add well-known libraries like Bootstrap or jQuery to a prototype or demo with a single script tag, avoiding any bundler setup.$q$, $q$Frontend developers and hobbyist coders building quick demos$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$Tutorials and code-sharing platforms$q$, $q$Educational content and tools like CodePen or JSFiddle commonly reference cdnjs URLs so example code runs immediately without local setup.$q$, $q$Educators, technical writers, and online coding communities$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$Lightweight websites without npm tooling$q$, $q$Small business or informational websites without a modern JavaScript build process use cdnjs to include necessary libraries directly via HTML.$q$, $q$Small website owners and freelance web developers$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$history-and-ownership$q$, $q$History and Ownership Transition to Cloudflare$q$, 2, ARRAY[$q$cdnjs began as a side project in January 2011, created by developers Ryan Kirkman and Thomas Davis who wanted an easy way for the web development community to load common JavaScript and CSS libraries from a fast, reliable, centrally hosted location instead of everyone self-hosting the same files repeatedly. The project's code was published publicly on GitHub on February 25, 2011, inviting community contributions almost from the start, which is part of why its library catalog grew so quickly in its early years.$q$, $q$Just months after launch, on June 15, 2011, cdnjs entered a partnership with Cloudflare, which provided the global CDN infrastructure needed to actually serve files quickly around the world, along with the now-familiar cdnjs.cloudflare.com subdomain. That partnership continued for roughly eight years until November 1, 2019, when Kirkman and Davis formally handed full ownership and day-to-day operation of cdnjs over to Cloudflare entirely, citing technical and commercial reasons tied to the project's scale. Since then, Cloudflare has run cdnjs as a fully free public service while the project's library list continues to be maintained through open, community-driven contributions on GitHub.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('dac93ca8-8c32-4123-94ac-09b9cd060986', $q$how-developers-use-it$q$, $q$How Developers Actually Use cdnjs$q$, 2, ARRAY[$q$In practice, using cdnjs requires no signup, account, or configuration: a developer browses or searches the library catalog at cdnjs.com, copies the provided script or link tag for the specific library and version they need, and pastes it into their HTML. From that point forward, Cloudflare's globally distributed edge network handles caching and delivering that file to visitors from a nearby location, which typically improves load times compared to hosting the file on a single origin server, and it also means popular libraries are often already cached in a visitor's browser from having loaded the same file on another site using cdnjs.$q$, $q$Because the service is free, open source, and backed by Cloudflare's infrastructure rather than a monetized product with usage tiers, cdnjs is most commonly used for quick prototyping, learning projects, smaller websites without a modern build pipeline, and situations where a team wants to avoid bundling a large dependency into their own JavaScript build. Larger, more complex applications increasingly rely on npm-based bundlers instead, but cdnjs remains a staple reference point across tutorials, code examples (such as on CodePen or JSFiddle), and any project that wants to add a well-known library with a single line of HTML.$q$]::text[], 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$Pages (word processing)$q$, $q$A long-form document editor for writing and editing text-based documents with real-time collaboration.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$Sheets (spreadsheets)$q$, $q$A spreadsheet tool for structured, tabular data, supporting the same real-time collaborative editing as pages.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$Bare-metal, jurisdiction-specific hosting$q$, $q$Data is hosted on independent bare-metal servers, currently in Montreal, Quebec, under Canadian and Quebec law, with more country options planned through 2027.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$No AI training on user content$q$, $q$The company explicitly commits to never using stored user documents to train AI models or extracting content for other purposes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$One-click public publishing$q$, $q$Any document can be published instantly to a shareable public link without additional configuration.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$Multi-format export$q$, $q$Documents can be exported to Markdown, PDF, Microsoft Word, CSV, or plain text, avoiding proprietary file lock-in.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$Real-time email-based collaboration$q$, $q$Collaborators are invited by email and can edit documents together in real time with live syncing.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$REST API access$q$, $q$Developers can access and manipulate cDox documents programmatically through a REST API.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$Explicit, publicly stated commitment that user content is never used for AI training or data mining$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$Data hosted under a specific national jurisdiction (currently Canada) on independent bare-metal servers rather than a large multinational cloud provider$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$Affordable Pro tier pricing at $8/month or $70/year compared to many mainstream productivity suites$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$Multi-format export (Markdown, PDF, Word, CSV) avoids proprietary file lock-in$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$Clear focus on privacy-sensitive professions like journalism, healthcare, and research gives it a distinct, differentiated value proposition$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$As an early-stage company, long-term business stability and feature parity with major competitors like Google Docs are unproven$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$Free tier storage (50MB) and public link limit (3) are quite restrictive for anything beyond light personal use$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$Currently hosted only in Canada, so the multi-country data residency roadmap (through 2027) is not yet available$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$Smaller feature set and integration ecosystem compared to mature, decades-old productivity suites$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$Limited public information on the company's security certifications or compliance posture for regulated industries like healthcare$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$What is cDox?$q$, $q$cDox is a privacy-first document and spreadsheet collaboration platform, built by Canadian company BFH Labs Inc., positioned as an alternative to Google Docs and Microsoft 365 for users who want data sovereignty and a guarantee that their content is never used to train AI models.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$Where is cDox data hosted?$q$, $q$Currently, all cDox data is hosted on independent bare-metal servers in Montreal, Quebec, Canada, under Canadian and Quebec law. The company plans to expand hosting to France, Germany, the UK, Switzerland, and Australia through 2027, eventually letting users choose their data's country of residence.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$Does cDox use my documents to train AI?$q$, $q$No. cDox explicitly states that user content is never used to train AI models and is never extracted or mined for any other purpose.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$How much does cDox cost?$q$, $q$cDox offers a Free tier with 50MB of storage and up to 3 public links, and a Pro tier at $8/month or $70/year with 500MB of storage and unlimited public links.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$What file formats can I export from cDox?$q$, $q$cDox documents can be exported to Markdown, PDF, Microsoft Word, CSV, and plain text formats.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$Does cDox support real-time collaboration?$q$, $q$Yes. Users can invite collaborators by email and edit documents together in real time, with changes syncing live across all participants.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$Who is cDox designed for?$q$, $q$cDox targets users and organizations where data privacy and jurisdictional control matter most, including writers, journalists, researchers, developers, editors, therapists, healthcare providers, nonprofits, and educators.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$Is cDox suitable for enterprise or regulated industries like healthcare?$q$, $q$cDox markets itself to healthcare providers and similar privacy-sensitive professions, but as an early-stage company it has limited publicly disclosed compliance certifications, so organizations in regulated industries should independently verify its security and compliance posture before adopting it for regulated data.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$Privacy-conscious writing and journalism$q$, $q$Writers and journalists use cDox to draft and store sensitive material with a guarantee it will not be mined for AI training or extracted for other purposes.$q$, $q$Independent writers, journalists, and authors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$Client-confidential documentation for healthcare and therapy practices$q$, $q$Therapists and healthcare providers use cDox's jurisdiction-specific hosting and no-AI-training policy for notes and documentation involving client confidentiality.$q$, $q$Therapists, healthcare providers, and small clinical practices$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$Data-sovereign collaboration for nonprofits and researchers$q$, $q$Nonprofits and academic researchers use cDox to collaborate on documents while keeping data under a specific national legal jurisdiction rather than a multinational cloud provider.$q$, $q$Nonprofit organizations and academic researchers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$Free$q$, $q$$0$q$, $q$Free$q$, NULL, $q$["50MB of storage","Up to 3 public shareable links","Pages and sheets document types","Real-time collaboration via email invitations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$Pro$q$, $q$$8/month or $70/year$q$, $q$Monthly or annual$q$, NULL, $q$["500MB of storage","Unlimited public shareable links","All Free tier features included","Priority access to new country hosting options as they launch"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$data-sovereignty-model$q$, $q$The Data Sovereignty Model at the Core of cDox$q$, 2, ARRAY[$q$What sets cDox apart from mainstream productivity suites like Google Docs or Microsoft 365 is not a novel editing feature but a fundamentally different stance on where and under what legal jurisdiction user data lives, and what it can be used for. Rather than hosting documents in a large multinational cloud provider's data centers subject to that provider's terms of service and jurisdiction, cDox currently stores all content on independent bare-metal servers physically located in Montreal, Quebec, placing user data explicitly under Canadian and Quebec law. The company has publicly committed that user content is never used to train AI models and is never extracted or mined for any secondary commercial purpose, a direct response to growing concern among writers, journalists, researchers, and privacy-conscious professionals about how their work might otherwise be used by large AI-focused technology companies.$q$, $q$Beyond its current Montreal hosting, cDox has stated plans to expand its infrastructure to additional countries, including France, Germany, the United Kingdom, Switzerland, and Australia, through 2027, with the long-term goal of letting users actively choose which country's servers and legal framework their documents are stored under. This kind of user-selectable data residency is uncommon even among enterprise-grade productivity tools, and reflects cDox's positioning toward users and organizations for whom jurisdictional control over sensitive documents is a genuine requirement rather than a nice-to-have.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd04a7a4-cff0-4b34-a27a-1888f1d00286', $q$features-and-audience$q$, $q$Core Features and Who cDox Is Built For$q$, 2, ARRAY[$q$Functionally, cDox provides the two document types most users need day to day: pages for word-processing style long-form writing, and sheets for spreadsheet-style structured data, both with real-time collaborative editing via email-based invitations. Documents auto-save continuously, can be published with one click to a shareable public link, and can be exported into Markdown, PDF, Word, or CSV formats so users are never locked into a proprietary file format. Additional touches like dark mode, keyboard shortcuts, threaded comments, and REST API access round out the feature set for both casual writers and more technical users who want to integrate cDox into their own workflows.$q$, $q$Given its privacy-first and data-sovereignty positioning, cDox's stated target users skew toward professions where confidentiality and control over content genuinely matter: writers and journalists concerned about source protection or having their unpublished drafts feed AI training data, researchers and academics handling sensitive study material, therapists and healthcare providers with client confidentiality obligations, and nonprofits and educators who prefer to avoid dependence on large technology platforms. For general-purpose office productivity without those specific privacy priorities, mainstream tools like Google Docs or Microsoft 365 will typically still offer a broader and more mature feature set; cDox's value proposition is specifically about trading some of that breadth for jurisdictional control and an explicit no-AI-training commitment.$q$]::text[], 1);
