-- ── CatchDoms ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$CatchDoms is an expired and pending-delete domain discovery platform built for domain investors, SEO professionals, and entrepreneurs looking to find valuable dropped or auctioned domains. It aggregates listings from roughly 16-20 domain auction platforms, including GoDaddy, Dynadot, DropCatch, SnapNames, Catched, and Gname, alongside a database of over 100,000 aged ccTLD domains available to register at standard price, adding tens of thousands of newly discovered domains every day. Every domain is automatically enriched with SEO and authority metrics such as Trust Flow, Citation Flow, Domain Authority, backlink counts, referring domains, and Wayback Machine history, so buyers can gauge a domain's value before bidding rather than manually checking each metric across separate tools. CatchDoms was built and is operated by a solo, bootstrapped founder, Samir Belabbes, who previously spent over a decade in SEO and web development and built the tool to solve his own workflow problem of checking a dozen auction platforms and multiple SEO tools every morning. Beyond the web interface, CatchDoms offers a REST API and a Model Context Protocol (MCP) server, letting developers and AI assistants like Claude or Cursor query expired-domain data programmatically or conversationally. Pricing includes a free tier showing limited visible domains, and a paid Pro plan around EUR 39 per month billed annually (EUR 89 per month billed monthly, or EUR 468 per year), with higher Authority and Authority plus tiers adding features like the aged-ccTLD regfee database and founder access.$q$, short_description),
  pricing_model = COALESCE($q$Freemium with tiered paid subscriptions (Free, Pro, Authority, Authority plus)$q$, pricing_model),
  starting_price = COALESCE($q$EUR 39/month (Pro plan billed annually; EUR 89/month billed monthly, or EUR 468/year)$q$, starting_price),
  founded_year = COALESCE(2024, founded_year),
  company_size = COALESCE($q$1 (solo, bootstrapped founder-operated project)$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed (independently operated, bootstrapped project)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$CatchDoms Review 2026: Expired Domain Finder and API for Domain Investors$q$, seo_title),
  seo_meta_description = COALESCE($q$A detailed look at CatchDoms, the expired and dropped domain discovery platform: features, pricing, API and MCP access, and who it is built for.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CatchDoms is an expired-domain intelligence platform designed to help domain investors, SEO professionals, and entrepreneurs find valuable dropped, deleted, or auctioned domain names without manually checking dozens of separate auction sites and SEO tools every day. The platform aggregates domain listings from a wide range of auction and registrar platforms, sources cited across its own materials range from roughly ten to twenty platforms including GoDaddy, Dynadot, DropCatch, SnapNames, Catched, Gname, BloomUp, UKBackorder, and DomainLore, and also maintains a database of more than 100,000 aged ccTLD domains that are available to register directly at standard registration price rather than through an auction. The service reports adding tens of thousands of newly discovered domains each day, with a total live inventory in the hundreds of thousands, and every domain listing is automatically enriched with SEO and authority signals such as Trust Flow and Citation Flow (Majestic metrics), Domain Authority, backlink counts, referring domain counts, category classification, domain age, and historical Wayback Machine snapshots, so a buyer can assess whether a domain is worth bidding on without pulling each metric manually from separate tools like Majestic or Ahrefs. CatchDoms was built and continues to be run by a solo, bootstrapped founder, Samir Belabbes, who has described spending over a decade in SEO and web development before building the tool to solve his own recurring problem as a domain investor: checking around a dozen different auction platforms each morning, running each candidate domain through Majestic, and then manually digging through the Wayback Machine to check its history, a workflow he consolidated into a single searchable platform with built-in filtering by domain length, TLD, language, technical stack, and category. Because the product is described publicly as a one-person, pre-seed, bootstrapped SaaS business rather than a venture-backed company, exact founding date, headquarters, and team size are not formally published; available evidence, including the site's own blog and developer write-ups, points to the platform being a relatively recent launch, likely dating to around 2024, though an exact founding date could not be independently confirmed and should be treated as an estimate rather than a verified fact. Beyond its web search interface, CatchDoms exposes a REST API for developers who want to integrate expired-domain data into their own scripts, spreadsheets, or acquisition pipelines, as well as a Model Context Protocol (MCP) server that lets AI coding assistants and agents such as Claude, Cursor, and Windsurf query expired-domain data conversationally, for example asking an AI assistant to find recently dropped domains in a specific niche with strong backlink profiles. On pricing, CatchDoms uses a freemium model: the free tier shows a limited number of visible domains (reported around ten) as a preview of the database, while the paid Pro plan unlocks full access to the live database and costs roughly EUR 39 per month when billed annually (equivalent to EUR 468 per year), or EUR 89 per month on a month-to-month basis. Above Pro, the platform also offers Authority and Authority plus tiers; Authority is described as adding access to the aged-ccTLD regfee database of domains registrable at standard price, a quarterly call with the founder, and early access to an upcoming post-auction monitoring feature, while exact public pricing for the Authority and Authority plus tiers was not confirmed in available sources at the time of this profile and should not be assumed without checking the current pricing page directly.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd1c3bb57-a99a-486b-8024-b9dcc1367a4d';

