-- ── cDox ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$cDox is a privacy-first document and spreadsheet collaboration platform positioned as a Google Docs and Microsoft 365 alternative for users who want their data kept out of AI training pipelines and hosted under data-sovereign legal jurisdiction. Built by BFH Labs Inc., a Canadian company, cDox currently hosts all user data on independent bare-metal servers physically located in Montreal, Quebec, governed by Canadian and Quebec law, with plans to expand hosting to additional countries, including France, Germany, the UK, Switzerland, and Australia, through 2027, so users will eventually be able to choose which country's jurisdiction their data lives under. The platform combines word-processing (pages) and spreadsheet (sheets) functionality with real-time collaboration via email invitations, auto-saving, one-click publishing to shareable public links, export options to Markdown, PDF, Word, and CSV, plus features like dark mode, keyboard shortcuts, threaded comments, and REST API access. Its core promise, stated explicitly by the company, is that user content is never used to train AI models and is never extracted or mined for other purposes. cDox targets writers, journalists, researchers, developers, editors, therapists, healthcare providers, nonprofits, and educators, groups for whom data privacy and jurisdictional control matter more than the deepest possible feature set. Pricing is freemium: a Free tier offers 50MB of storage and up to 3 public links, while the Pro tier costs $8 per month or $70 per year and unlocks 500MB of storage and unlimited public links.$q$, short_description),
  pricing_model = COALESCE($q$Freemium subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free (Pro plan available at $8/month or $70/year)$q$, starting_price),
  founded_year = COALESCE(2024, founded_year),
  company_size = COALESCE($q$Small, early-stage startup (exact headcount not publicly disclosed)$q$, company_size),
  headquarters = COALESCE($q$Montreal, Quebec, Canada$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$cDox Review 2026: A Privacy-First Google Docs Alternative With Data Sovereignty$q$, seo_title),
  seo_meta_description = COALESCE($q$What is cDox? A look at the Canadian, privacy-first document and spreadsheet platform: features, pricing, data sovereignty model, and who it is built for.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$cDox is a document and spreadsheet collaboration platform built around the core idea of data sovereignty and privacy, positioning itself as an alternative to Google Docs, Google Sheets, and Microsoft 365 for individuals and organizations that specifically do not want their documents used to train AI models or hosted under jurisdictions and legal frameworks they cannot control. The product is made by BFH Labs Inc., a Canadian company, and the founder has publicly framed the project's mission around what the company describes as de-big-teching, an approach rooted in open web principles that pushes back against large technology platforms mining user content for AI training or advertising purposes. At present, cDox hosts all user data exclusively on independent bare-metal servers physically located in Montreal, Quebec, meaning the data is governed under Canadian and Quebec law rather than the jurisdiction of a large multinational cloud provider. The company has stated plans to expand its hosting footprint to additional countries, including France, Germany, the United Kingdom, Switzerland, and Australia, through 2027, with the eventual goal of letting users choose which country's servers and legal jurisdiction their documents are stored under, a feature not commonly offered by mainstream productivity suites. Functionally, cDox combines two core document types: pages, a word-processing style document for long-form writing, and sheets, a spreadsheet tool for structured or tabular data, both supporting real-time collaboration where users invite collaborators by email and see edits sync live. Documents auto-save continuously to the underlying bare-metal infrastructure, and users can publish any document with one click to generate a shareable public link, or export it in common formats including Markdown, PDF, Microsoft Word, CSV, and plain text, ensuring content is not locked into a proprietary format. Additional features include a dark mode interface, keyboard shortcuts for power users, threaded commenting for collaborative feedback, and REST API access for developers who want to integrate cDox documents into other tools or workflows. The company's most emphasized commitment is that user content is never used to train AI models and is never extracted or mined by the company for any secondary purpose, a direct point of differentiation from major productivity suites that have faced scrutiny over how user content may be used in relation to AI training. Given this positioning, cDox's stated target audience includes writers, journalists, researchers, developers, editors, therapists, healthcare providers, nonprofits, and educators, professions and organizations where confidentiality, source protection, client privacy, or simply a philosophical preference against feeding personal or professional writing into AI training pipelines carries real weight. On pricing, cDox follows a freemium subscription model: the Free tier includes 50MB of storage and up to 3 public shareable links, sufficient for casual or exploratory use, while the paid Pro tier costs $8 per month or $70 per year (a modest discount for annual billing) and unlocks 500MB of storage along with unlimited public links, aimed at more active writers, small teams, or organizations that need more capacity and unrestricted sharing. As a relatively young, early-stage company without extensive public financial or team-size disclosures, prospective users evaluating cDox for sensitive or regulated use cases, such as healthcare or legal documentation, should independently verify its current compliance posture and security practices rather than assuming parity with larger, more established enterprise productivity platforms.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fd04a7a4-cff0-4b34-a27a-1888f1d00286';

